import {
  aboutMarquee,
  awardMarquee,
  brandHover,
  initAwwardAnimation,
  initFloatingCTA,
  initGalleryAnimation,
  initLoad,
  initPixelSection,
  initSectionOverlapFull,
  initSectionOverlapNext,
  initSectionOverlapPrev,
  initSectionOverlapScalePrev,
  initServiceHover,
  initSwiper,
  initWorkHomepage,
  navControl,
  reviewMarquee,
  workMarquee,
  testiCustomMouse,
  workSectionTransition,
  initTeam,
  initFooter,
} from './animations/hatypo-revamp';
import { initAos, initAosScale, initStaggeredAos } from './plugins/aos';
import { initCounter } from './plugins/counter';
import { initTrFlip } from './plugins/flip-scrub';
import { initLenis } from './plugins/lenis';
import { getLenis } from './plugins/lenis';
import { initTrMarquee } from './plugins/scroll-marquee';
import { initFooterOverlap, initSectionOverlapHalf } from './plugins/section-overlap';
import { showHideGrid } from './plugins/showHideGrid';
import { createSplitText, initFadeEatchWordOnScroll, splitLines } from './plugins/split-text';

CustomEase.create('primary-ease', '0.62, 0.05, 0.01, 0.99');
CustomEase.create('primary-ease-out', '0.17,0.84,0.44,1');
CustomEase.create('smooth', '.15, .9, .34, .95');
CustomEase.create('custom', '.76, 0, .24, 1');

ScrollTrigger.defaults({
  markers: false,
  scroller: document.documentElement,
});

function initTeamMarquee() {
  const wrapper = document.querySelector('[team-marquee]');
  if (!wrapper) return;

  const marquee = wrapper.querySelector('.running-scrub-wrap');

  const contentWidth = marquee.scrollWidth;
  const moveWidth = contentWidth / 5;

  gsap.set(marquee, { x: '80vw' });

  const tl = gsap.timeline({
    scrollTrigger: {
      trigger: marquee,
      start: 'top bottom',
      end: 'bottom top',
      scrub: true,
    },
  });

  tl.to(marquee, {
    x: -moveWidth,
    duration: 1,
    ease: 'none',
  });
}

function initModal() {
  const button = document.querySelector('[modal-open]');
  if (!button) return;
  const closeButton = document.querySelector('[modal-close]');
  const modalContainer = document.querySelector('.modal-video');
  const background = document.querySelector('.modal-background');
  const modal = document.querySelector('.modal-main');
  const content = document.querySelector('.reels-wrapper');
  const { body } = document;

  // timeline (paused dulu)

  const tl = gsap.timeline({
    paused: true,
  });

  tl.set(modalContainer, { pointerEvents: 'auto' })
    .to(
      background,
      {
        backgroundColor: 'rgba(0,0,0,0.7)',
        duration: 0.4,
        ease: 'power2.out',
      },
      0
    )
    .to(
      content,
      {
        scale: 0.9,
        duration: 0.4,
        ease: 'power2.out',
      },
      0
    )
    .to(
      modal,
      {
        y: 0,
        scale: 1,
        opacity: 1,
        duration: 0.5,
        ease: 'power3.out',
      },
      0.1
    );

  // OPEN
  button.addEventListener('click', () => {
    body.classList.add('modal-active');
    tl.play();
  });

  // CLOSE (klik background)
  closeButton.addEventListener('click', (e) => {
    tl.reverse();

    tl.eventCallback('onReverseComplete', () => {
      // gsap.set(closeButton, { pointerEvents: 'none' });
      body.classList.remove('modal-active');
    });
  });
}

function initApp() {
  const mm = gsap.matchMedia();

  initLenis();
  window.lenis = getLenis();
  showHideGrid();
  //reusable functions
  splitLines();
  initFadeEatchWordOnScroll();
  createSplitText();
  initAos();
  initAosScale();
  initStaggeredAos();
  initTrMarquee();
  initTrFlip();
  initCounter();

  // Hatypo Revamp Animations
  initGalleryAnimation();
  initPixelSection();
  initWorkHomepage();
  initServiceHover();
  initAwwardAnimation();
  // initServiceTransition();
  reviewMarquee();
  aboutMarquee();
  initSectionOverlapScalePrev();
  initSwiper();
  //navControl();
  testiCustomMouse();
  brandHover();
  initFloatingCTA();
  awardMarquee();
  workMarquee();
  workSectionTransition();

  //about page
  initTeam();
  initTeamMarquee();

  initLoad();
  initFooter();
  initModal();

  mm.add('(min-width: 992px)', () => {
    initSectionOverlapPrev();
    initSectionOverlapNext();
    initSectionOverlapFull();
    initSectionOverlapHalf();
    initFooterOverlap();
  });
}

if (document.readyState === 'complete') {
  initApp();
} else {
  window.addEventListener('load', initApp);
}

window.onload = function () {
  window.scrollTo({
    top: 0,
    left: 0,
    behavior: 'smooth', // For smooth animation
  });

  // ScrollTrigger.refresh();
};

document.addEventListener('resize', () => {
  ScrollTrigger.refresh();
});
